import type {
  CompanyListResponse,
  Company,
  InvestorListResponse,
  Investor,
  Stats,
  Filters,
  ScrapeLog,
  SearchParams,
} from "./types";

const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";

async function fetchJson<T>(path: string, init?: RequestInit): Promise<T> {
  const res = await fetch(`${API_BASE}${path}`, {
    ...init,
    headers: { "Content-Type": "application/json", ...init?.headers },
  });
  if (!res.ok) {
    throw new Error(`API error: ${res.status} ${res.statusText}`);
  }
  return res.json();
}

export async function fetchCompanies(
  params: SearchParams
): Promise<CompanyListResponse> {
  const sp = new URLSearchParams();
  if (params.q) sp.set("q", params.q);
  if (params.sector) sp.set("sector", params.sector);
  if (params.stage) sp.set("stage", params.stage);
  if (params.investor) sp.set("investor", params.investor);
  if (params.investor_id) sp.set("investor_id", String(params.investor_id));
  if (params.location) sp.set("location", params.location);
  if (params.sort) sp.set("sort", params.sort);
  if (params.page) sp.set("page", String(params.page));
  if (params.per_page) sp.set("per_page", String(params.per_page));

  return fetchJson<CompanyListResponse>(`/api/companies?${sp.toString()}`);
}

export async function fetchCompany(slug: string): Promise<Company> {
  return fetchJson<Company>(`/api/companies/${slug}`);
}

export async function fetchInvestors(
  type?: string
): Promise<InvestorListResponse> {
  const sp = new URLSearchParams();
  if (type) sp.set("type", type);
  return fetchJson<InvestorListResponse>(`/api/investors?${sp.toString()}`);
}

export async function fetchInvestor(id: number): Promise<Investor> {
  return fetchJson<Investor>(`/api/investors/${id}`);
}

export async function fetchStats(): Promise<Stats> {
  return fetchJson<Stats>("/api/stats");
}

export async function fetchFilters(): Promise<Filters> {
  return fetchJson<Filters>("/api/filters");
}

export async function fetchScrapeLogs(limit = 50): Promise<ScrapeLog[]> {
  return fetchJson<ScrapeLog[]>(`/api/scrape/logs?limit=${limit}`);
}

export async function triggerScrape(
  investorId: number
): Promise<{ message: string }> {
  return fetchJson<{ message: string }>(`/api/scrape/${investorId}`, {
    method: "POST",
  });
}

export async function triggerScrapeAll(): Promise<{ message: string }> {
  return fetchJson<{ message: string }>("/api/scrape/all", {
    method: "POST",
  });
}

