"use client";

import { useRouter, useSearchParams } from "next/navigation";
import { useQuery } from "@tanstack/react-query";
import { fetchFilters } from "@/lib/api";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";

export function FilterSidebar() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const { data: filters } = useQuery({
    queryKey: ["filters"],
    queryFn: fetchFilters,
  });

  const activeSectors = searchParams.get("sector")?.split(",").filter(Boolean) || [];
  const activeStages = searchParams.get("stage")?.split(",").filter(Boolean) || [];

  function toggleFilter(key: string, value: string) {
    const params = new URLSearchParams(searchParams.toString());
    const current = params.get(key)?.split(",").filter(Boolean) || [];
    const idx = current.indexOf(value);
    if (idx >= 0) {
      current.splice(idx, 1);
    } else {
      current.push(value);
    }
    if (current.length > 0) {
      params.set(key, current.join(","));
    } else {
      params.delete(key);
    }
    params.delete("page");
    router.push(`/?${params.toString()}`);
  }

  function clearAll() {
    router.push("/");
  }

  const hasFilters = activeSectors.length > 0 || activeStages.length > 0;

  if (!filters) return null;

  return (
    <aside className="w-full space-y-4">
      <div className="flex items-center justify-between">
        <h3 className="text-sm font-semibold">Filters</h3>
        {hasFilters && (
          <button
            onClick={clearAll}
            className="text-xs text-muted-foreground hover:text-foreground"
          >
            Clear all
          </button>
        )}
      </div>

      {filters.sectors.length > 0 && (
        <>
          <div>
            <h4 className="text-xs font-medium text-muted-foreground mb-2 uppercase tracking-wider">
              Sector
            </h4>
            <div className="flex flex-wrap gap-1.5">
              {filters.sectors.map((sector) => (
                <Badge
                  key={sector}
                  variant={activeSectors.includes(sector) ? "default" : "outline"}
                  className="cursor-pointer text-xs"
                  onClick={() => toggleFilter("sector", sector)}
                >
                  {sector}
                </Badge>
              ))}
            </div>
          </div>
          <Separator />
        </>
      )}

      {filters.stages.length > 0 && (
        <div>
          <h4 className="text-xs font-medium text-muted-foreground mb-2 uppercase tracking-wider">
            Stage
          </h4>
          <div className="flex flex-wrap gap-1.5">
            {filters.stages.map((stage) => (
              <Badge
                key={stage}
                variant={activeStages.includes(stage) ? "default" : "outline"}
                className="cursor-pointer text-xs"
                onClick={() => toggleFilter("stage", stage)}
              >
                {stage}
              </Badge>
            ))}
          </div>
        </div>
      )}
    </aside>
  );
}

