"use client";

import { useSearchParams } from "next/navigation";
import { useQuery } from "@tanstack/react-query";
import { LayoutGrid, List } from "lucide-react";
import { Suspense, useState } from "react";
import { fetchCompanies, fetchStats } from "@/lib/api";
import { SearchBar } from "@/components/SearchBar";
import { FilterSidebar } from "@/components/FilterSidebar";
import { CompanyCard } from "@/components/CompanyCard";
import { DataTable } from "@/components/DataTable";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";

function HomeContent() {
  const searchParams = useSearchParams();
  const [viewMode, setViewMode] = useState<"grid" | "table">("grid");

  const params = {
    q: searchParams.get("q") || undefined,
    sector: searchParams.get("sector") || undefined,
    stage: searchParams.get("stage") || undefined,
    investor: searchParams.get("investor") || undefined,
    sort: searchParams.get("sort") || "newest",
    page: Number(searchParams.get("page")) || 1,
    per_page: 24,
  };

  const { data, isLoading } = useQuery({
    queryKey: ["companies", params],
    queryFn: () => fetchCompanies(params),
  });

  const { data: stats } = useQuery({
    queryKey: ["stats"],
    queryFn: fetchStats,
  });

  return (
    <div className="container mx-auto px-4 py-8">
      {/* Hero / Search */}
      <div className="text-center mb-8 space-y-4">
        <h1 className="text-3xl font-bold tracking-tight">
          Startup Portfolio Aggregator
        </h1>
        <p className="text-muted-foreground">
          {stats
            ? `Tracking ${stats.total_companies.toLocaleString()} startups across ${stats.total_investors} investors`
            : "Search and browse startup portfolios across top VCs and accelerators"}
        </p>
        <div className="flex justify-center">
          <SearchBar />
        </div>
      </div>

      <div className="flex flex-col lg:flex-row gap-6">
        {/* Sidebar */}
        <div className="lg:w-56 shrink-0">
          <FilterSidebar />
        </div>

        {/* Main content */}
        <div className="flex-1 space-y-4">
          {/* Toolbar */}
          <div className="flex items-center justify-between">
            <p className="text-sm text-muted-foreground">
              {data ? `${data.total.toLocaleString()} companies` : "Loading..."}
            </p>
            <div className="flex items-center gap-1">
              <Button
                variant={viewMode === "grid" ? "default" : "ghost"}
                size="icon"
                onClick={() => setViewMode("grid")}
                className="h-8 w-8"
              >
                <LayoutGrid className="h-4 w-4" />
              </Button>
              <Button
                variant={viewMode === "table" ? "default" : "ghost"}
                size="icon"
                onClick={() => setViewMode("table")}
                className="h-8 w-8"
              >
                <List className="h-4 w-4" />
              </Button>
            </div>
          </div>

          {/* Results */}
          {isLoading ? (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {Array.from({ length: 6 }).map((_, i) => (
                <Skeleton key={i} className="h-48 rounded-lg" />
              ))}
            </div>
          ) : data && data.items.length > 0 ? (
            <>
              {viewMode === "grid" ? (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                  {data.items.map((company) => (
                    <CompanyCard key={company.id} company={company} />
                  ))}
                </div>
              ) : (
                <DataTable companies={data.items} />
              )}

              {/* Pagination */}
              {data.total_pages > 1 && (
                <div className="flex justify-center gap-2 pt-6">
                  {Array.from({ length: Math.min(data.total_pages, 10) }).map(
                    (_, i) => {
                      const pageNum = i + 1;
                      const sp = new URLSearchParams(searchParams.toString());
                      sp.set("page", String(pageNum));
                      return (
                        <Button
                          key={pageNum}
                          variant={
                            pageNum === data.page ? "default" : "outline"
                          }
                          size="sm"
                          asChild
                        >
                          <a href={`/?${sp.toString()}`}>{pageNum}</a>
                        </Button>
                      );
                    }
                  )}
                </div>
              )}
            </>
          ) : (
            <div className="text-center py-16">
              <p className="text-muted-foreground text-lg">
                No companies found
              </p>
              <p className="text-sm text-muted-foreground mt-1">
                Try adjusting your search or filters
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default function HomePage() {
  return (
    <Suspense>
      <HomeContent />
    </Suspense>
  );
}

