input.content:
"use client";

import { useParams } from "next/navigation";
import { useQuery } from "@tanstack/react-query";
import Link from "next/link";
import {
  ArrowLeft,
  ExternalLink,
  MapPin,
  Calendar,
  Building2,
} from "lucide-react";
import { fetchCompany } from "@/lib/api";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import { Skeleton } from "@/components/ui/skeleton";

export default function CompanyDetailPage() {
  const { slug } = useParams<{ slug: string }>();
  const { data: company, isLoading } = useQuery({
    queryKey: ["company", slug],
    queryFn: () => fetchCompany(slug),
    enabled: !!slug,
  });

  if (isLoading) {
    return (
      <div className="container mx-auto px-4 py-8 max-w-3xl space-y-4">
        <Skeleton className="h-8 w-48" />
        <Skeleton className="h-24 w-full" />
        <Skeleton className="h-48 w-full" />
      </div>
    );
  }

  if (!company) {
    return (
      <div className="container mx-auto px-4 py-16 text-center">
        <p className="text-lg text-muted-foreground">Company not found</p>
        <Button asChild variant="ghost" className="mt-4">
          <Link href="/">Back to search</Link>
        </Button>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8 max-w-3xl">
      <Button asChild variant="ghost" size="sm" className="mb-6">
        <Link href="/">
          <ArrowLeft className="h-4 w-4 mr-1" />
          Back
        </Link>
      </Button>

      {/* Header */}
      <div className="space-y-4 mb-8">
        <div className="flex items-start justify-between gap-4">
          <h1 className="text-3xl font-bold">{company.name}</h1>
          {company.website && (
            <Button asChild variant="outline" size="sm">
              <a
                href={company.website}
                target="_blank"
                rel="noopener noreferrer"
              >
                <ExternalLink className="h-3.5 w-3.5 mr-1" />
                Website
              </a>
            </Button>
          )}
        </div>

        <div className="flex flex-wrap gap-2">
          {company.sector && (
            <Badge variant="secondary">{company.sector}</Badge>
          )}
          {company.stage && <Badge variant="outline">{company.stage}</Badge>}
          {company.status && company.status !== "active" && (
            <Badge variant="destructive">{company.status}</Badge>
          )}
        </div>

        {company.description && (
          <p className="text-muted-foreground text-lg">
            {company.description}
          </p>
        )}
      </div>

      {/* Key Facts */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
        {company.location && (
          <div className="flex items-center gap-2 text-sm text-muted-foreground">
            <MapPin className="h-4 w-4 shrink-0" />
            {company.location}
          </div>
        )}
        {company.founded_year && (
          <div className="flex items-center gap-2 text-sm text-muted-foreground">
            <Calendar className="h-4 w-4 shrink-0" />
            Founded {company.founded_year}
          </div>
        )}
        {company.employee_count && (
          <div className="flex items-center gap-2 text-sm text-muted-foreground">
            <Building2 className="h-4 w-4 shrink-0" />
            {company.employee_count} employees
          </div>
        )}
      </div>

      {company.long_description && (
        <>
          <Separator className="mb-6" />
          <div className="mb-8">
            <h2 className="text-lg font-semibold mb-3">About</h2>
            <p className="text-muted-foreground leading-relaxed">
              {company.long_description}
            </p>
          </div>
        </>
      )}

      {/* Investors */}
      {company.investors.length > 0 && (
        <>
          <Separator className="mb-6" />
          <div>
            <h2 className="text-lg font-semibold mb-4">
              Backed by ({company.investors.length})
            </h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              {company.investors.map((inv) => (
                <Link key={inv.id} href={`/investors/${inv.id}`}>
                  <Card className="hover:shadow-sm transition-shadow cursor-pointer">
                    <CardHeader className="py-3 px-4">
                      <CardTitle className="text-sm font-medium flex items-center justify-between">
                        {inv.name}
                        <Badge variant="outline" className="text-xs">
                          {inv.type}
                        </Badge>
                      </CardTitle>
                    </CardHeader>
                  </Card>
                </Link>
              ))}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

