input.content:
"use client";

import { useParams } from "next/navigation";
import { useQuery, useMutation } from "@tanstack/react-query";
import Link from "next/link";
import {
  ArrowLeft,
  ExternalLink,
  MapPin,
  RefreshCw,
  Building2,
} from "lucide-react";
import { fetchInvestor, fetchCompanies, triggerScrape } from "@/lib/api";
import { CompanyCard } from "@/components/CompanyCard";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { Skeleton } from "@/components/ui/skeleton";
import { useState } from "react";

export default function InvestorDetailPage() {
  const { id } = useParams<{ id: string }>();
  const investorId = Number(id);
  const [page, setPage] = useState(1);

  const { data: investor, isLoading: investorLoading } = useQuery({
    queryKey: ["investor", investorId],
    queryFn: () => fetchInvestor(investorId),
    enabled: !!investorId,
  });

  const { data: companies, isLoading: companiesLoading } = useQuery({
    queryKey: ["investor-companies", investorId, page],
    queryFn: () =>
      fetchCompanies({ investor_id: investorId, page, per_page: 24 }),
    enabled: !!investorId,
  });

  const scrapeMutation = useMutation({
    mutationFn: () => triggerScrape(investorId),
  });

  if (investorLoading) {
    return (
      <div className="container mx-auto px-4 py-8 max-w-5xl space-y-4">
        <Skeleton className="h-8 w-48" />
        <Skeleton className="h-24 w-full" />
      </div>
    );
  }

  if (!investor) {
    return (
      <div className="container mx-auto px-4 py-16 text-center">
        <p className="text-lg text-muted-foreground">Investor not found</p>
        <Button asChild variant="ghost" className="mt-4">
          <Link href="/investors">Back to investors</Link>
        </Button>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8 max-w-5xl">
      <Button asChild variant="ghost" size="sm" className="mb-6">
        <Link href="/investors">
          <ArrowLeft className="h-4 w-4 mr-1" />
          Investors
        </Link>
      </Button>

      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-start sm:justify-between gap-4 mb-8">
        <div className="space-y-2">
          <div className="flex items-center gap-3">
            <h1 className="text-3xl font-bold">{investor.name}</h1>
            <Badge variant="outline">{investor.type}</Badge>
          </div>

          <div className="flex flex-wrap gap-4 text-sm text-muted-foreground">
            {investor.location && (
              <span className="flex items-center gap-1">
                <MapPin className="h-3.5 w-3.5" />
                {investor.location}
              </span>
            )}
            <span className="flex items-center gap-1">
              <Building2 className="h-3.5 w-3.5" />
              {investor.portfolio_count} companies
            </span>
          </div>

          {investor.last_scraped_at && (
            <p className="text-xs text-muted-foreground">
              Last scraped:{" "}
              {new Date(investor.last_scraped_at).toLocaleString()}
            </p>
          )}
        </div>

        <div className="flex gap-2">
          {investor.website && (
            <Button asChild variant="outline" size="sm">
              <a
                href={investor.website}
                target="_blank"
                rel="noopener noreferrer"
              >
                <ExternalLink className="h-3.5 w-3.5 mr-1" />
                Website
              </a>
            </Button>
          )}
          <Button
            variant="default"
            size="sm"
            onClick={() => scrapeMutation.mutate()}
            disabled={scrapeMutation.isPending}
          >
            <RefreshCw
              className={`h-3.5 w-3.5 mr-1 ${scrapeMutation.isPending ? "animate-spin" : ""}`}
            />
            {scrapeMutation.isPending ? "Scraping..." : "Scrape Now"}
          </Button>
        </div>
      </div>

      {scrapeMutation.isSuccess && (
        <div className="bg-green-50 dark:bg-green-950 text-green-800 dark:text-green-200 px-4 py-2 rounded-md text-sm mb-6">
          Scrape started! Results will appear shortly.
        </div>
      )}

      <Separator className="mb-6" />

      {/* Portfolio */}
      <h2 className="text-lg font-semibold mb-4">Portfolio Companies</h2>

      {companiesLoading ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {Array.from({ length: 6 }).map((_, i) => (
            <Skeleton key={i} className="h-48 rounded-lg" />
          ))}
        </div>
      ) : companies && companies.items.length > 0 ? (
        <>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {companies.items.map((company) => (
              <CompanyCard key={company.id} company={company} />
            ))}
          </div>

          {companies.total_pages > 1 && (
            <div className="flex justify-center gap-2 pt-6">
              <Button
                variant="outline"
                size="sm"
                disabled={page <= 1}
                onClick={() => setPage((p) => p - 1)}
              >
                Previous
              </Button>
              <span className="flex items-center text-sm text-muted-foreground px-2">
                Page {page} of {companies.total_pages}
              </span>
              <Button
                variant="outline"
                size="sm"
                disabled={page >= companies.total_pages}
                onClick={() => setPage((p) => p + 1)}
              >
                Next
              </Button>
            </div>
          )}
        </>
      ) : (
        <p className="text-center text-muted-foreground py-12">
          No portfolio companies yet. Click &quot;Scrape Now&quot; to fetch
          data.
        </p>
      )}
    </div>
  );
}

